import React, { useEffect, useRef, useState } from 'react'
import { API }         from '../../api'
import { useNavigate } from 'react-router-dom'

/* ─── table styles ─────────────────────────────────────────────── */
const th  = { border:'1px solid #ccc', padding:10, textAlign:'left' }
const td  = { border:'1px solid #eee', padding:10 }
const btn = { width:28, height:28, margin:'0 4px',
              border:'1px solid #ccc', background:'#fff', cursor:'pointer' }

const Return = () => {
  const [stocks, setStocks] = useState([])   // остатки на складе
  const [sales,  setSales]  = useState([])   // все продажи с items
  const [cart,   setCart]   = useState([])   // что возвращаем
  const [reason, setReason] = useState('defect')
  const inputRef            = useRef()
  const navigate            = useNavigate()

  /* сумма возврата */
  const total = cart.reduce((s,i)=>s + i.qty*+i.price, 0)

  /* ─── грузим склад + продажи ────────────────────────────────── */
  useEffect(() => {
    API.getStocks().then(r => setStocks(r.data))
    API.getSales ({ with_items:true }).then(r => setSales(r.data))
  }, [])

  /* ─── сканирование ──────────────────────────────────────────── */
  const handleScan = e => {
    if (e.key !== 'Enter') return
    const code = e.target.value.trim()
    if (!code) return

    /* 1) находим товар на складе */
    const stockItem = stocks.find(s => s.code === code)
    if (!stockItem){ alert('Товар не найден'); e.target.value=''; return }

    /* 2) ищем последнюю продажу этой позиции,
          берём её sale_item.id — именно его ждёт backend */
    const saleItem = sales
      .flatMap(s => s.items)               // массив всех позиций
      .filter(i => i.code === code)        // только нужный код
      .sort((a,b)=> new Date(b.date)-new Date(a.date))[0] // последняя

    if (!saleItem){
      alert('Sale item не найден — чек не пробивался?')
      e.target.value=''; return
    }

    setCart(prev=>{
      const ex = prev.find(p=>p.sale_item === saleItem.id)
      return ex
        ? prev.map(p=>p.sale_item===saleItem.id ? {...p,qty:p.qty+1}:p)
        : [...prev,{ ...stockItem, qty:1, sale_item:saleItem.id }]
    })
    e.target.value=''
  }

  /* ─── qty helpers ───────────────────────────────────────────── */
  const changeQty = (idx, d)=>
    setCart(p=>p.map((r,i)=>
      i===idx?{...r,qty:Math.max(1,r.qty+d)}:r))
  const setQty = (idx,val)=>
    setCart(p=>p.map((r,i)=>
      i===idx?{...r,qty:Math.max(1,parseInt(val)||1)}:r))
  const remove = idx => setCart(p=>p.filter((_,i)=>i!==idx))

  /* ─── отправка ──────────────────────────────────────────────── */
  const handleReturn = async ()=>{
    if(!cart.length) return alert('Корзина пуста')

    const payload = {
      reason,
      items: cart.map(i=>({ sale_item:i.sale_item, quantity:i.qty }))
    }

    try{
      await API.createReturn(payload)
      alert('Возврат оформлен')
      setCart([])
      navigate('/returns-report')
    }catch(err){
      console.error(err)
      alert('Ошибка при возврате')
    }
  }

  /* ─── UI ────────────────────────────────────────────────────── */
  return(
    <div style={{padding:24,maxWidth:900,margin:'0 auto',fontFamily:'sans-serif'}}>
      <h2>🔄 Возврат товара</h2>

      <input
        ref={inputRef} autoFocus
        placeholder="Сканируйте штрихкод…"
        onKeyDown={handleScan}
        style={{width:'100%',padding:12,fontSize:16,marginBottom:20}}
      />

      <div style={{marginBottom:20}}>
        <label>Причина:&nbsp;</label>
        <select value={reason} onChange={e=>setReason(e.target.value)}>
          <option value="defect">Дефект</option>
          <option value="customer">Покупатель вернул</option>
          <option value="expiry">Истёк срок годности</option>
        </select>
      </div>

      <table style={{width:'100%',borderCollapse:'collapse',marginBottom:20}}>
        <thead style={{background:'#f0f0f0'}}>
          <tr><th style={th}>Название</th><th style={th}>Цена</th>
              <th style={th}>Кол-во</th><th style={th}>Сумма</th><th style={th}></th></tr>
        </thead>
        <tbody>
          {cart.map((it,idx)=>(
            <tr key={idx}>
              <td style={td}>{it.name}</td>
              <td style={td}>{(+it.price).toFixed(2)} сом</td>
              <td style={td}>
                <button onClick={()=>changeQty(idx,-1)} style={btn}>−</button>
                <input type="number" min={1} value={it.qty}
                       onChange={e=>setQty(idx,e.target.value)}
                       style={{width:50,textAlign:'center'}}/>
                <button onClick={()=>changeQty(idx, +1)} style={btn}>+</button>
              </td>
              <td style={td}>{(it.qty*+it.price).toFixed(2)} сом</td>
              <td style={td}>
                <button onClick={()=>remove(idx)}
                        style={{...btn,background:'#ff4d4f',color:'#fff'}}>×</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <h3 style={{textAlign:'right'}}>К возврату: {total.toFixed(2)} сом</h3>

      <div style={{textAlign:'right',marginTop:20}}>
        <button onClick={handleReturn}
                style={{background:'#f39c12',color:'#fff',
                        padding:'10px 20px',border:'none',cursor:'pointer'}}>
          🛒 Оформить возврат
        </button>
      </div>
    </div>
  )
}

export default Return
